```csharp
using System;
using System.IO;
using UnityEngine;
using UnityEngine.Rendering;

[RequireComponent(typeof(MeshFilter), typeof(MeshRenderer))]
public class AsiaHeightMeshGenerator : MonoBehaviour
{
    [Header("高度文件")]
    [SerializeField] private string fileName = "asia_height_2048x1307.bin";

[Header("原始数据尺寸")]
[SerializeField] private int sourceWidth = 2048;
[SerializeField] private int sourceHeight = 1307;

[Header("地图尺寸")]
[SerializeField] private float mapWidth = 600f;
[SerializeField] private float mapDepth = 383f;
[SerializeField] private float heightScale = 35f;

[Header("采样")]
[Min(1)]
[SerializeField] private int sampleStep = 6;

[Header("平滑")]
[Min(0)]
[SerializeField] private int smoothIterations = 2;

private void Start()
{
    GenerateMesh();
}

private void GenerateMesh()
{
    string filePath = Path.Combine(Application.streamingAssetsPath, fileName);

if (!File.Exists(filePath))
{
    Debug.LogError($"找不到高度文件：{filePath}");
    return;
}

byte[] rawBytes;
try
{
    rawBytes = File.ReadAllBytes(filePath);
}
catch (Exception e)
{
    Debug.LogError($"读取高度文件失败：{e.Message}");
    return;
}

int expectedByteCount = sourceWidth * sourceHeight * 2;
if (rawBytes.Length != expectedByteCount)
{
    Debug.LogError(
        $"文件大小不正确。期望 {expectedByteCount} 字节，实际 {rawBytes.Length} 字节。"
    );
    return;
}

if (smoothIterations > 0 && smoothRadius > 0)
{
    heights = SmoothHeightField(heights, gridWidth, gridHeight, smoothIterations, smoothRadius);
}

for (int z = 0; z < gridHeight; z++)
{
    for (int x = 0; x < gridWidth; x++)
    {
        int i = z * gridWidth + x;
        float normalizedHeight = heights[i];

float worldX =
    mapWidth * 0.5f
    - x / (float)(gridWidth - 1) * mapWidth;

float worldZ =
    z / (float)(gridHeight - 1) * mapDepth
    - mapDepth * 0.5f;

vertices[i] = new Vector3(
    worldX,
    normalizedHeight * heightScale,
    worldZ
);

        uv[i] = new Vector2(
            x / (float)(gridWidth - 1),
            1f - z / (float)(gridHeight - 1)
        );
    }
}

for (int z = 0; z < gridHeight - 1; z++)
{
    for (int x = 0; x < gridWidth - 1; x++)
    {
        int bottomLeft = z * gridWidth + x;
        int bottomRight = bottomLeft + 1;
        int topLeft = bottomLeft + gridWidth;
        int topRight = topLeft + 1;

triangles[triangleIndex++] = bottomLeft;
triangles[triangleIndex++] = bottomRight;
triangles[triangleIndex++] = topLeft;

        triangles[triangleIndex++] = bottomRight;
        triangles[triangleIndex++] = topRight;
        triangles[triangleIndex++] = topLeft;
    }
}

Mesh mesh = new Mesh
{
    name = "Asia Height Mesh",
    indexFormat = IndexFormat.UInt32
};

mesh.vertices = vertices;
mesh.triangles = triangles;
mesh.uv = uv;
mesh.RecalculateNormals();
mesh.RecalculateBounds();

    Debug.Log(
        $"亚洲地形生成完成：{gridWidth} × {gridHeight}，顶点数 {vertices.Length:N0}"
    );
}

private float[] SampleHeightField(byte[] rawBytes, int gridWidth, int gridHeight)
{
    float[] heights = new float[gridWidth * gridHeight];

for (int z = 0; z < gridHeight; z++)
{
    int sourceZ = Mathf.Min(z * sampleStep, sourceHeight - 1);

for (int x = 0; x < gridWidth; x++)
{
    int sourceX = Mathf.Min(x * sampleStep, sourceWidth - 1);
    int byteIndex = (sourceZ * sourceWidth + sourceX) * 2;

ushort rawHeight = (ushort)(
    rawBytes[byteIndex] |
    (rawBytes[byteIndex + 1] << 8)
);

        heights[z * gridWidth + x] = rawHeight / 65535f;
    }
}

private float[] SmoothHeightField(
    float[] source,
    int width,
    int height,
    int iterations,
    int radius
)
{
    float[] current = (float[])source.Clone();
    float[] result = new float[source.Length];

for (int iteration = 0; iteration < iterations; iteration++)
{
    for (int z = 0; z < height; z++)
    {
        for (int x = 0; x < width; x++)
        {
            float center = current[z * width + x];

float left = current[
    z * width + Mathf.Max(x - 1, 0)
];

float right = current[
    z * width + Mathf.Min(x + 1, width - 1)
];

float down = current[
    Mathf.Max(z - 1, 0) * width + x
];

float up = current[
    Mathf.Min(z + 1, height - 1) * width + x
];

float downLeft = current[
    Mathf.Max(z - 1, 0) * width +
    Mathf.Max(x - 1, 0)
];

float downRight = current[
    Mathf.Max(z - 1, 0) * width +
    Mathf.Min(x + 1, width - 1)
];

float upLeft = current[
    Mathf.Min(z + 1, height - 1) * width +
    Mathf.Max(x - 1, 0)
];

float upRight = current[
    Mathf.Min(z + 1, height - 1) * width +
    Mathf.Min(x + 1, width - 1)
];

        // 高斯式权重：
        // 1 2 1
        // 2 4 2
        // 1 2 1
        result[z * width + x] =
            (
                center * 4f +
                left * 2f +
                right * 2f +
                down * 2f +
                up * 2f +
                downLeft +
                downRight +
                upLeft +
                upRight
            ) / 16f;
    }
}

    float[] swap = current;
    current = result;
    result = swap;
}

        return current;
    }
}
```

items.bodyMarkdown:
QGIS 是一款界面友好、功能完整的开源地理信息系统。本文将以亚洲区域为例，介绍如何从 QGIS 和 GEBCO 获取地形高程数据，完成裁剪、海平面处理、降采样与 16 位归一化，并最终在 Unity 中生成可渲染的三维地形网格。

QGIS 从 3.32 版本开始，在“高程剖面”工具中加入了导出能力，可将剖面结果导出为以下形式：

- **3D 要素（3D Features）**：包含高程值的三维剖面线。
- **2D 剖面图（2D Profile）**：距离与高程组成的二维图表。
- **距离/高程表格（Distance/Elevation Table）**：沿剖面采样得到的数据表格。
- **常用导出格式**：DXF、CSV、Shapefile、GeoPackage 等。

这些功能适用于道路、河流、管线等线路的地形起伏分析，也可作为游戏地图与三维可视化项目的数据准备工具。

QGIS 官网：<https://www.qgis.org/>

![QGIS 界面](/uploads/gallery/mr31kr0w-4c060c79491b23f5.png)

## 一、加载世界地图

1. 在左侧 **Browser（浏览器）** 面板中找到并展开：

   ```text
   XYZ Tiles
   ```

2. 找到 **OpenStreetMap**。
3. 双击 **OpenStreetMap**，等待地图加载完成。

加载成功后，主视图中会显示世界地图。

## 二、切换到经纬度坐标系

![切换坐标参考系](/uploads/gallery/mr31qb94-dc123e74f03308b0.png)

1. 点击 QGIS 右下角当前显示的坐标参考系，例如 `EPSG:3857`。
2. 在搜索框中输入：

   ```text
   4326
   ```

3. 选择：

   ```text
   WGS 84 / EPSG:4326
   ```

4. 点击 **OK（确定）**。

`EPSG:4326` 使用经纬度坐标，便于后续按照明确的经纬度范围裁剪亚洲区域。

## 三、打开处理工具箱

在顶部菜单中依次点击：

```text
Processing → Toolbox
```

右侧会出现 **Processing Toolbox（处理工具箱）** 面板，其中包含一个搜索框。后续的数据范围创建、栅格转换等操作都将在这里完成。

## 四、创建亚洲区域范围图层

在 **Processing Toolbox** 顶部的搜索框中输入：

```text
Create layer from extent
```

双击搜索结果中的 **Create layer from extent**，打开参数窗口。该工具可以根据指定的经纬度范围创建一个矩形矢量图层。

![创建范围图层](/uploads/gallery/mr31vcpe-61fd90ab6f8ec6a1.png)

在 **Extent** 中输入：

```text
56,150,5,65 [EPSG:4326]
```

参数顺序为：

```text
最小经度, 最大经度, 最小纬度, 最大纬度
```

执行工具后，在左下角图层列表中右键生成的 `Extent` 图层，依次选择：

```text
Export → Save Features As...
```

将该范围图层保存到本地，后续可用于确认和复用下载范围。

![导出范围图层](/uploads/gallery/mr32bj63-30c8505b74e1bd8c.png)

## 五、下载并加载 GEBCO 高程数据

在浏览器中搜索：

```text
GEBCO grid download
```

进入 GEBCO 数据下载页面，并按照前面确定的经纬度范围下载栅格高程数据。

![GEBCO 数据下载范围](/uploads/gallery/mr38or0a-cff88c242ad31d63.png)

下载完成后，将 GeoTIFF 文件拖入 QGIS，或通过 **Layer → Add Layer → Add Raster Layer** 加载。

![在 QGIS 中加载 GEBCO 数据](/uploads/gallery/mr38x1yr-c57fbbd1da4fbc5e.png)

## 六、将海洋区域压平到 0

在顶部菜单中依次点击：

```text
Raster → Raster Calculator
```

为了避免海底负高程在 Unity 中形成巨大的“海沟”，需要将所有小于 0 的像素统一设为 0，同时保留陆地区域的原始高程。

在 **Raster Calculator Expression** 中输入：

```text
if("gebco_2026_n65.0_s5.0_w56.0_e150.0_geotiff@1" < 0, 0, "gebco_2026_n65.0_s5.0_w56.0_e150.0_geotiff@1")
```

表达式的逻辑如下：

```text
海拔小于 0 → 设置为 0
海拔大于或等于 0 → 保持原值
```

> 图层名称应与当前 QGIS 项目中的实际栅格图层名称一致。

![使用栅格计算器压平海洋](/uploads/gallery/mr38yigg-4d276261b6c2dec3.png)

点击 **Output layer** 右侧的 `...`，将结果保存为：

```text
D:\AsiaStrategyMap\Data\Processed\asia_land_only.tif
```

如果 `Processed` 文件夹尚不存在，请先创建。设置完成后点击 **确定**，等待计算完成。

## 七、降低栅格分辨率

原始 GEBCO 栅格通常较大，直接用于 Unity 会产生过多顶点和较高的内存开销，因此需要先进行降采样。

在右侧 **Processing Toolbox** 中搜索：

```text
Translate (convert format)
```

双击打开该工具。在部分中文界面中，它可能显示为：

```text
Translate (convert format) / 转换（转换格式）
```

展开：

```text
Advanced Parameters
```

在 **Additional command-line parameters [optional]** 中输入：

```text
-outsize 2048 1307 -r bilinear
```

参数含义：

- `-outsize 2048 1307`：将输出尺寸设置为 `2048 × 1307`。
- `-r bilinear`：使用双线性重采样，减轻缩小后山脉边缘的锯齿感。

`2048 × 1307` 基本保持了当前 `94° × 60°` 地理范围的长宽比例。

![设置 GDAL 降采样参数](/uploads/gallery/mr390ip5-b2c59ebaccc7d8d6.png)

在 **Converted** 输出项右侧点击 `...`，保存为：

```text
D:\AsiaStrategyMap\Data\Processed\asia_land_2048.tif
```

此时 **Output data type** 保持：

```text
Use Input Layer Data Type
```

完成设置后运行转换。

## 八、确认输出分辨率

在左侧图层列表中右键 `asia_land_2048`，选择：

```text
Properties → Information
```

检查以下字段：

```text
Width / Columns
Height / Rows
```

正常情况下，输出尺寸应接近：

```text
2048 × 1307
```

![确认栅格分辨率](/uploads/gallery/mr38txes-e1f7e62dcf5ac75a.png)

## 九、将高程归一化为 16 位数据

Unity 可以方便地读取 `0～65535` 范围的 16 位无符号整数高度数据，因此需要先对高程进行归一化。

再次打开 **Raster Calculator**，在表达式中输入：

```text
("asia_land_2048@1" / 6132.527832) * 65535
```

其中，`6132.527832` 是当前栅格数据中的最大高程值。使用其他数据时，应根据该栅格的实际最大值进行替换。

将计算结果保存为新的 GeoTIFF 文件。随后，再次打开：

```text
Translate (convert format)
```

将 **Input layer** 设置为刚刚生成的归一化结果图层，例如：

```text
calcal
```

找到 **Output data type**，将其从：

```text
Use Input Layer Data Type
```

修改为：

```text
UInt16
```

![将输出类型设置为 UInt16](/uploads/gallery/mr3966et-3b515e268b2bd532.png)

建议将结果保存为：

```text
D:\AsiaStrategyMap\asia_height_uint16.tif
```

## 十、转换为 16 位 RAW 文件

Unity 可以通过 `TextureFormat.R16` 或直接读取二进制数据的方式处理单通道 16 位高度图。

打开 `OSGeo4W.bat`，执行：

```bash
gdal_translate -of ENVI -ot UInt16 "D:\AsiaStrategyMap\asia_height_uint16.tif" "D:\AsiaStrategyMap\asia_height_2048x1307.bin"
```

该命令会将 GeoTIFF 转换为 ENVI 格式，并生成 `.bin` 数据文件及对应的 `.hdr` 描述文件。Unity 侧主要读取 `.bin` 文件。

## 十一、在 Unity 中生成地形网格

### 1. 创建脚本 `AsiaHeightMeshGenerator`

在 Unity 项目中创建脚本 `AsiaHeightMeshGenerator.cs`，写入以下代码：

```csharp
using System;
using System.IO;
using UnityEngine;
using UnityEngine.Rendering;

[RequireComponent(typeof(MeshFilter), typeof(MeshRenderer))]
public class AsiaHeightMeshGenerator : MonoBehaviour
{
    [Header("高度文件")]
    [SerializeField] private string fileName = "asia_height_2048x1307.bin";

    [Header("原始数据尺寸")]
    [SerializeField] private int sourceWidth = 2048;
    [SerializeField] private int sourceHeight = 1307;

    [Header("地图尺寸")]
    [SerializeField] private float mapWidth = 600f;
    [SerializeField] private float mapDepth = 383f;
    [SerializeField] private float heightScale = 35f;

    [Header("采样")]
    [Min(1)]
    [SerializeField] private int sampleStep = 6;

    [Header("平滑")]
    [Min(0)]
    [SerializeField] private int smoothIterations = 2;

    [Min(0)]
    [SerializeField] private int smoothRadius = 1;

    private void Start()
    {
        GenerateMesh();
    }

    private void GenerateMesh()
    {
        string filePath = Path.Combine(Application.streamingAssetsPath, fileName);

        if (!File.Exists(filePath))
        {
            Debug.LogError($"找不到高度文件：{filePath}");
            return;
        }

        byte[] rawBytes;
        try
        {
            rawBytes = File.ReadAllBytes(filePath);
        }
        catch (Exception e)
        {
            Debug.LogError($"读取高度文件失败：{e.Message}");
            return;
        }

        int expectedByteCount = sourceWidth * sourceHeight * 2;
        if (rawBytes.Length != expectedByteCount)
        {
            Debug.LogError(
                $"文件大小不正确。期望 {expectedByteCount} 字节，实际 {rawBytes.Length} 字节。"
            );
            return;
        }

        int gridWidth = Mathf.CeilToInt((sourceWidth - 1) / (float)sampleStep) + 1;
        int gridHeight = Mathf.CeilToInt((sourceHeight - 1) / (float)sampleStep) + 1;

        float[] heights = SampleHeightField(rawBytes, gridWidth, gridHeight);

        if (smoothIterations > 0 && smoothRadius > 0)
        {
            heights = SmoothHeightField(heights, gridWidth, gridHeight, smoothIterations, smoothRadius);
        }

        Vector3[] vertices = new Vector3[gridWidth * gridHeight];
        Vector2[] uv = new Vector2[vertices.Length];

        for (int z = 0; z < gridHeight; z++)
        {
            for (int x = 0; x < gridWidth; x++)
            {
                int i = z * gridWidth + x;
                float normalizedHeight = heights[i];

                float worldX =
                    mapWidth * 0.5f
                    - x / (float)(gridWidth - 1) * mapWidth;

                float worldZ =
                    z / (float)(gridHeight - 1) * mapDepth
                    - mapDepth * 0.5f;

                vertices[i] = new Vector3(
                    worldX,
                    normalizedHeight * heightScale,
                    worldZ
                );

                uv[i] = new Vector2(
                    x / (float)(gridWidth - 1),
                    1f - z / (float)(gridHeight - 1)
                );
            }
        }

        int[] triangles = new int[(gridWidth - 1) * (gridHeight - 1) * 6];
        int triangleIndex = 0;

        for (int z = 0; z < gridHeight - 1; z++)
        {
            for (int x = 0; x < gridWidth - 1; x++)
            {
                int bottomLeft = z * gridWidth + x;
                int bottomRight = bottomLeft + 1;
                int topLeft = bottomLeft + gridWidth;
                int topRight = topLeft + 1;

                triangles[triangleIndex++] = bottomLeft;
                triangles[triangleIndex++] = bottomRight;
                triangles[triangleIndex++] = topLeft;

                triangles[triangleIndex++] = bottomRight;
                triangles[triangleIndex++] = topRight;
                triangles[triangleIndex++] = topLeft;
            }
        }

        Mesh mesh = new Mesh
        {
            name = "Asia Height Mesh",
            indexFormat = IndexFormat.UInt32
        };

        mesh.vertices = vertices;
        mesh.triangles = triangles;
        mesh.uv = uv;
        mesh.RecalculateNormals();
        mesh.RecalculateBounds();

        GetComponent<MeshFilter>().sharedMesh = mesh;

        Debug.Log(
            $"亚洲地形生成完成：{gridWidth} × {gridHeight}，顶点数 {vertices.Length:N0}"
        );
    }

    private float[] SampleHeightField(byte[] rawBytes, int gridWidth, int gridHeight)
    {
        float[] heights = new float[gridWidth * gridHeight];

        for (int z = 0; z < gridHeight; z++)
        {
            int sourceZ = Mathf.Min(z * sampleStep, sourceHeight - 1);

            for (int x = 0; x < gridWidth; x++)
            {
                int sourceX = Mathf.Min(x * sampleStep, sourceWidth - 1);
                int byteIndex = (sourceZ * sourceWidth + sourceX) * 2;

                ushort rawHeight = (ushort)(
                    rawBytes[byteIndex] |
                    (rawBytes[byteIndex + 1] << 8)
                );

                heights[z * gridWidth + x] = rawHeight / 65535f;
            }
        }

        return heights;
    }

    private float[] SmoothHeightField(
        float[] source,
        int width,
        int height,
        int iterations,
        int radius
    )
    {
        float[] current = (float[])source.Clone();
        float[] result = new float[source.Length];

        for (int iteration = 0; iteration < iterations; iteration++)
        {
            for (int z = 0; z < height; z++)
            {
                for (int x = 0; x < width; x++)
                {
                    float center = current[z * width + x];

                    float left = current[
                        z * width + Mathf.Max(x - 1, 0)
                    ];

                    float right = current[
                        z * width + Mathf.Min(x + 1, width - 1)
                    ];

                    float down = current[
                        Mathf.Max(z - 1, 0) * width + x
                    ];

                    float up = current[
                        Mathf.Min(z + 1, height - 1) * width + x
                    ];

                    float downLeft = current[
                        Mathf.Max(z - 1, 0) * width +
                        Mathf.Max(x - 1, 0)
                    ];

                    float downRight = current[
                        Mathf.Max(z - 1, 0) * width +
                        Mathf.Min(x + 1, width - 1)
                    ];

                    float upLeft = current[
                        Mathf.Min(z + 1, height - 1) * width +
                        Mathf.Max(x - 1, 0)
                    ];

                    float upRight = current[
                        Mathf.Min(z + 1, height - 1) * width +
                        Mathf.Min(x + 1, width - 1)
                    ];

                    // 高斯式权重：
                    // 1 2 1
                    // 2 4 2
                    // 1 2 1
                    result[z * width + x] =
                        (
                            center * 4f +
                            left * 2f +
                            right * 2f +
                            down * 2f +
                            up * 2f +
                            downLeft +
                            downRight +
                            upLeft +
                            upRight
                        ) / 16f;
                }
            }

            float[] swap = current;
            current = result;
            result = swap;
        }

        return current;
    }
}
```

该脚本会完成以下工作：

- 从 `StreamingAssets` 读取 16 位高度数据；
- 按照 `sampleStep` 对原始数据进行采样；
- 对采样后的高度场执行平滑处理；
- 生成顶点、UV 与三角形索引；
- 创建 Unity `Mesh` 并赋值给当前对象的 `MeshFilter`。

### 2. 配置脚本参数

将脚本挂载到一个同时包含 `MeshFilter` 与 `MeshRenderer` 的 GameObject 上，并按照项目需求配置地图尺寸、高度缩放、采样步长和平滑次数。

![AsiaHeightMeshGenerator 参数](/uploads/gallery/mr3e31xp-0d1fc6cf45ef2491.png)

### 3. 放置高度数据文件

在 Unity 项目中创建以下目录：

```text
Assets/StreamingAssets
```

将 `asia_height_2048x1307.bin` 放入该目录，并确保脚本中的 `fileName`、`sourceWidth` 和 `sourceHeight` 与实际文件一致。

![将 BIN 文件放入 StreamingAssets](/uploads/gallery/mr3dxkkh-4cb431ee9144b084.png)

### 4. 创建地形与海洋材质

分别创建两个材质：

```text
AsiaTerrainMaterial
OceanMaterial
```

将 `AsiaTerrainMaterial` 赋给地形网格，将 `OceanMaterial` 赋给海平面对象。

![地形材质](/uploads/gallery/mr3e0d7h-45ae142e4ae9ffb1.png)

![海洋材质](/uploads/gallery/mr3e0m4d-43fa4f646ae16737.png)

## 十二、放置海平面

创建一个平面对象，并设置以下 Transform 参数：

| 属性 | 数值 |
| --- | --- |
| Position | `Vector3(0, 0.05, 0)` |
| Rotation | `Vector3(0, 0, 0)` |
| Scale | `Vector3(60, 0.1, 38.2)` |

海平面的 Y 坐标略高于 `0`，可以减少与地形零高度区域发生 Z-Fighting 的概率。

## 十三、最终效果

完成数据处理、网格生成、材质配置与海平面放置后，即可在 Unity 中得到亚洲区域的三维地形效果。

